#include <stdio.h>
#include <stdlib.h>

typedef struct {int s;int e;long long c;} Event;

int cmpEnd(const void *a, const void *b){
    Event *x=(Event*)a, *y=(Event*)b;
    return x->e - y->e;
}

int binarySearch(Event *ev, int n, int start){
    int lo=0, hi=n-1, ans=-1;
    while(lo<=hi){
        int mid=(lo+hi)/2;
        if(ev[mid].e <= start){ ans=mid; lo=mid+1; }
        else hi=mid-1;
    }
    return ans;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        Event *ev = (Event*)malloc(N*sizeof(Event));
        for(int i=0;i<N;i++) scanf("%d %d %lld", &ev[i].s, &ev[i].e, &ev[i].c);
        qsort(ev,N,sizeof(Event),cmpEnd);
        long long *dp = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++){
            long long incl = ev[i].c;
            int j = binarySearch(ev,i,ev[i].s);
            if(j!=-1) incl += dp[j];
            long long excl = (i==0)?0:dp[i-1];
            dp[i] = incl>excl?incl:excl;
        }
        printf("%lld\n", dp[N-1]);
        free(ev); free(dp);
    }
    return 0;
}

