import java.io.*;
import java.util.*;

public class Main {
    static class Event{int s,e; long c;}
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            int N = Integer.parseInt(br.readLine().trim());
            Event[] ev = new Event[N];
            for(int i=0;i<N;i++){
                st = new StringTokenizer(br.readLine());
                ev[i]=new Event();
                ev[i].s = Integer.parseInt(st.nextToken());
                ev[i].e = Integer.parseInt(st.nextToken());
                ev[i].c = Long.parseLong(st.nextToken());
            }
            Arrays.sort(ev, Comparator.comparingInt(o->o.e));
            int[] ends = new int[N];
            for(int i=0;i<N;i++) ends[i]=ev[i].e;
            long[] dp = new long[N];
            for(int i=0;i<N;i++){
                long incl = ev[i].c;
                int j = Arrays.binarySearch(ends, 0, i, ev[i].s);
                if(j<0) j = -j-2; // last index with end <= start
                if(j>=0) incl += dp[j];
                long excl = (i>0)?dp[i-1]:0;
                dp[i] = Math.max(incl,excl);
            }
            out.append(dp[N-1]).append('\n');
        }
        System.out.print(out.toString());
    }
}

