const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let tc = 0; tc < T; tc++) {
  const N = Number(input[idx++]);
  let events = [];
  for (let i = 0; i < N; i++) {
    const s = Number(input[idx++]);
    const e = Number(input[idx++]);
    const c = Number(input[idx++]);
    events.push({s, e, c});
  }
  events.sort((a, b) => a.e - b.e);
  const ends = events.map(ev => ev.e);
  const dp = new Array(N);
  for (let i = 0; i < N; i++) {
    let incl = events[i].c;
    let lo = 0, hi = i - 1, pos = -1;
    while (lo <= hi) {
      const mid = (lo + hi) >> 1;
      if (ends[mid] <= events[i].s) { pos = mid; lo = mid + 1; }
      else hi = mid - 1;
    }
    if (pos !== -1) incl += dp[pos];
    const excl = i ? dp[i - 1] : 0;
    dp[i] = incl > excl ? incl : excl;
  }
  outputs.push(String(dp[N - 1]));
}
console.log(outputs.join('\n'));
